r_ktm_loan_paid_cash_not_nest.sql:
SELECT tab_data.account_id, tab_data.account_name,
tab_data.principal_amount, tab_data.interest_amount, tab_data.item_amount, tab_data.loan_type from ( /* เงินกู้ */ SELECT sc_acc_m_account_master.account_id, sc_acc_m_account_master.account_name, sc_lon_m_contract.loan_type, sum( sc_com_m_receipt_item.principal_amount ) as principal_amount, sum( sc_com_m_receipt_item.interest_amount ) as interest_amount, sum( sc_com_m_receipt_item.item_amount) as item_amount , sc_com_m_receipt.receipt_date as receipt_date , sc_com_m_ucf_money_type.money_type_id as money_type_id ,sc_com_m_receipt.branch_id as branch_id FROM sc_com_m_receipt, sc_com_m_receipt_item, sc_lon_m_rule, sc_acc_m_account_master, sc_com_m_ucf_receipt_item_type ,sc_lon_m_contract ,sc_com_m_ucf_money_type ,sc_lon_m_contract_multi_paid WHERE ( sc_com_m_receipt_item.receipt_no = sc_com_m_receipt.receipt_no ) and ( sc_com_m_receipt_item.loan_type = sc_lon_m_rule.loan_type ) and ( sc_lon_m_rule.account_id = sc_acc_m_account_master.account_id ) and ( sc_com_m_receipt_item.item_type_id = sc_com_m_ucf_receipt_item_type.item_type_id ) and ( sc_com_m_receipt.receipt_status = '0' ) AND ( sc_com_m_ucf_receipt_item_type.group_item = 'LON' ) AND ( sc_com_m_receipt_item.item_amount <> 0 ) and sc_lon_m_contract.loan_contract_no = sc_com_m_receipt.loan_contract_no
--and sc_com_m_ucf_money_type.money_type_id = sc_lon_m_contract.type_pay_money and sc_com_m_ucf_money_type.money_type_id = sc_lon_m_contract_multi_paid.type_pay_money and sc_lon_m_contract_multi_paid.loan_contract_no = sc_lon_m_contract.loan_contract_no GROUP BY sc_acc_m_account_master.account_id, sc_acc_m_account_master.account_name, sc_com_m_receipt.receipt_date , sc_com_m_ucf_money_type.money_type_id ,sc_com_m_receipt.branch_id ,sc_lon_m_contract.loan_type union
SELECT sc_com_m_ucf_receipt_item_type.item_type_id as account_id , sc_com_m_ucf_receipt_item_type.item_type_name as account_name , '' as loan_type, sum( sc_com_m_receipt_item.principal_amount ) as principal_amount, sum( sc_com_m_receipt_item.interest_amount ) as interest_amount, sum( sc_com_m_receipt_item.item_amount) as item_amount , sc_com_m_receipt.receipt_date as receipt_date , sc_com_m_ucf_money_type.money_type_id as money_type_id ,sc_com_m_receipt.branch_id as branch_id FROM sc_com_m_receipt, sc_com_m_receipt_item, sc_com_m_ucf_receipt_item_type ,sc_lon_m_contract ,sc_com_m_ucf_money_type ,sc_lon_m_contract_multi_paid WHERE ( sc_com_m_receipt_item.receipt_no = sc_com_m_receipt.receipt_no ) and ( sc_com_m_receipt_item.item_type_id = sc_com_m_ucf_receipt_item_type.item_type_id ) and ( sc_com_m_receipt.receipt_status = '0' ) AND ( sc_com_m_ucf_receipt_item_type.group_item <> 'LON' ) AND ( sc_com_m_receipt_item.item_amount <> 0 ) and sc_lon_m_contract.loan_contract_no = sc_com_m_receipt.loan_contract_no and sc_com_m_ucf_money_type.money_type_id = sc_lon_m_contract_multi_paid.type_pay_money and sc_lon_m_contract_multi_paid.loan_contract_no = sc_lon_m_contract.loan_contract_no GROUP BY sc_com_m_ucf_receipt_item_type.item_type_id, sc_com_m_ucf_receipt_item_type.item_type_name , sc_com_m_receipt.receipt_date , sc_com_m_ucf_money_type.money_type_id ,sc_com_m_receipt.branch_id
) tab_data , sc_fin_m_close_day ,sc_com_m_ucf_money_type ,sc_com_m_branch where sc_fin_m_close_day.journal_date = tab_data.receipt_date and sc_com_m_ucf_money_type.money_type_id = tab_data.money_type_id and sc_fin_m_close_day.journal_date = {0} and sc_com_m_ucf_money_type.money_type_id not in ( 'CSH' , 'ATM' )
and sc_com_m_branch.branch_id = sc_fin_m_close_day.branch_fin and sc_com_m_branch.branch_id = tab_data.branch_id and sc_com_m_branch.branch_id = {1} and tab_data.loan_type = {2}
